package main

import (
	"net/http"
	"os"
	"path/filepath"
	"strings"
)

func fileHandler(w http.ResponseWriter, r *http.Request) {
	filename := r.URL.Query().Get("filename")
	if filename == "" {
		http.Error(w, "filename parameter is required", http.StatusBadRequest)
		return
	}

	// Canonicalize the filename to prevent path traversal
	normalizedFilename := filepath.Clean(filename)
	
	// Ensure the normalized path doesn't contain ".." or start with "/"
	if strings.Contains(normalizedFilename, "..") || strings.HasPrefix(normalizedFilename, "/") {
		http.Error(w, "invalid filename", http.StatusBadRequest)
		return
	}

	// Define the uploads directory
	uploadsDir := "./uploads"
	
	// Construct the full file path
	fullPath := filepath.Join(uploadsDir, normalizedFilename)
	
	// Ensure the file is within the uploads directory
	absUploadsDir, _ := filepath.Abs(uploadsDir)
	absFullPath, _ := filepath.Abs(fullPath)
	
	if !strings.HasPrefix(absFullPath, absUploadsDir) {
		http.Error(w, "access denied", http.StatusForbidden)
		return
	}

	// Check if file exists
	if _, err := os.Stat(fullPath); os.IsNotExist(err) {
		http.Error(w, "file not found", http.StatusNotFound)
		return
	}

	// Set appropriate content type based on file extension
	contentType := getContentType(fullPath)
	w.Header().Set("Content-Type", contentType)

	// Serve the file
	http.ServeFile(w, r, fullPath)
}

func getContentType(filename string) string {
	extension := filepath.Ext(filename)
	switch strings.ToLower(extension) {
	case ".jpg", ".jpeg":
		return "image/jpeg"
	case ".png":
		return "image/png"
	case ".gif":
		return "image/gif"
	case ".pdf":
		return "application/pdf"
	case ".txt":
		return "text/plain"
	case ".html", ".htm":
		return "text/html"
	case ".css":
		return "text/css"
	case ".js":
		return "application/javascript"
	case ".json":
		return "application/json"
	case ".xml":
		return "application/xml"
	case ".mp4":
		return "video/mp4"
	case ".mp3":
		return "audio/mpeg"
	case ".zip":
		return "application/zip"
	default:
		return "application/octet-stream"
	}
}

func main() {
	http.HandleFunc("/file", fileHandler)
	http.ListenAndServe(":8080", nil)
}